class Solution {
public:
    int strangePrinter(string s) {
        int n = s.length();
        if (n == 0) return 0;

        vector<vector<int>> dp(n, vector<int>(n, 0));

        for (int l = 1; l < n; ++l) {
            dp[l][l] = 1;
            for (int r = l + 1; r < n; ++r) {
                dp[l][r] = dp[l][r - 1] + 1;
                for (int k = l; k < r; ++k) {
                    if (s[k] == s[r]) {
                        if (dp[k + 1][r - 1] < dp[l][r]) {
                            dp[l][r] = dp[k + 1][r - 1] + 1;
                        }
                    }
                }
                if (s[l] == s[r]) {
                    if (dp[l][r - 1] < dp[l][r]) {
                        dp[l][r] = dp[l][r - 1];
                    }
                }
            }
        }

        return dp[0][n - 1];
    }
};

